def solve(words: Array[String]): Array[Long] = {
    if (words.length <= 1) return Array.emptyLongArray

    val answer = new Array[Long](words.length)

    for (i <- words.indices) {
        val filtered = words.take(i) ++ words.drop(i + 1)
        var maxLen = 0L

        for (j <- 0 until filtered.length - 1) {
            val s1 = filtered(j)
            val s2 = filtered(j + 1)
            var currentLen = 0L
            val minLength = math.min(s1.length, s2.length)

            while (currentLen < minLength && s1(currentLen.toInt) == s2(currentLen.toInt)) {
                currentLen += 1
            }

            if (currentLen > maxLen) {
                maxLen = currentLen
            }
        }

        answer(i) = maxLen
    }

    answer
}
